INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('14b23688-0db3-5ac9-a57a-fa21e59e6044', 'e4771d83-f771-49af-9ec0-1329cd777ef4', 'Due to global warming, the ice in the ___ is disappearing much faster than scientists previously expected.', '由於全球暖化，___ 的冰正在以比科學家先前預期快得多的速度消失。', 'Arctic Ocean', 'Pacific Ocean', 'Indian Ocean', 'Atlantic Ocean', 'Arctic 源自拉丁語 arktos (熊) → 指北極熊所在的區域；Ocean 源自希臘語 okeanos (廣大的水域)。', '想像在極地寒冷的環境中，只有北極熊 (Arctic) 能在廣大的海洋 (Ocean) 中生存。', '2026-07-06 23:42:13', '2026-07-06 23:42:13'),
('a0ed67fe-c6a5-59a7-aea9-a58a2085a29c', '56238401-177a-4cd9-9b27-e81206fe4ed7', 'The two research findings are remarkably ___, even though they were conducted by different teams.', '儘管是由不同的團隊進行的，但這兩項研究結果卻非常相似。', 'alike', 'acute', 'ample', 'aloof', 'a- (趨向/處於某種狀態) + like (相似的) → 處於相似的狀態 → 相似的。', 'a + like → 變得像一樣 → 相似的。', '2026-07-06 19:49:34', '2026-07-06 19:49:34'),
('629625bf-6c3c-5521-ba9e-217cea9d5f6c', '7e4281ce-b52f-4cdb-ab07-3ac98749a8d7', 'The instructions for the exam were filled with ___ , leaving many students confused about how to answer the questions.', '考試說明充滿了模稜兩可之處，讓許多學生對於如何回答問題感到困惑。', 'ambiguity', 'stability', 'efficiency', 'priority', 'ambi (兩者/雙重) + agere (驅動) + ity (名詞字尾) → 雙重意義 → 模稜兩可。', 'ambi (兩者) → 兩個意思都有可能 → 意義不明確。', '2026-07-06 20:39:04', '2026-07-06 20:39:04'),
('4c177d8a-2d5a-5185-9acf-53d29f76bcfc', 'a246cf3e-3610-404e-9acd-8c45ea3142a6', 'A dog is a common house ___.', '狗是一種常見的家畜。', 'animal', 'fruit', 'color', 'school', 'anim- (生命、靈魂)', 'anim (生命) + al (字尾) → 具有生命的生物 → 動物', '2026-07-06 14:15:10', '2026-07-06 14:15:10'),
('a55c4bc5-e76d-521d-a480-f0045a5e01c4', '372d875e-c1bc-4fc0-8f69-18bd8ac2bfcf', 'The doctor prescribed a strong ___ to help fight the bacterial infection in his throat.', '醫生開了一種強效的抗生素來幫助對抗他喉嚨的細菌感染。', 'antibiotic', 'vaccine', 'vitamin', 'bandage', 'anti- (反對/抗) + bio (生命/生物) + -tic (形容詞字尾) → 字面意思為「對抗生物（細菌）的」。', 'anti (反) + bio (生物) → 用來對抗生命（細菌）的藥物就是抗生素。', '2026-07-06 21:48:41', '2026-07-06 21:48:41'),
('004f121f-04fb-5c32-88c8-2fda6d1b56f4', '6d2c9989-c847-4d7f-a6a6-ec75a023187d', 'My grandfather likes to sit in a soft ___ to read books.', '我祖父喜歡坐在舒適的扶手椅上看書。', 'armchair', 'cupboard', 'table', 'clock', '由 arm (手臂) 與 chair (椅子) 組成的複合名詞。', '想像坐在椅子上，兩邊有手臂可以靠著 → armchair。', '2026-07-06 14:47:24', '2026-07-06 14:47:24'),
('ed15af8c-1f04-5755-bdf5-02852412ecbc', 'f1b5cab1-657a-4768-9011-0202a116ab5f', 'The heavy snow will ___ the road.', '大雪會阻塞道路。', 'block', 'clean', 'find', 'help', 'block 為單字本身，當動詞時表示「阻塞」或「擋住」。', '想像用積木 (blocks) 擋住路口。', '2026-07-07 04:03:44', '2026-07-07 04:03:44'),
('9827f335-40d7-52a1-801f-0d46c1918258', '0a4952ec-85a2-48e8-84f4-50d792f24daf', 'Excuse me, can we have the ___ please?', '不好意思，我們可以結帳嗎？', 'check', 'gift', 'song', 'dream', 'check 在此作為名詞，在餐廳情境中指帳單。', '記住 check 除了檢查，在餐廳也能用來叫帳。', '2026-07-07 03:28:55', '2026-07-07 03:28:55'),
('ab46d365-c9e8-5c65-8984-4f0a1e3ca2e4', 'd0c249b3-623d-4489-9110-de2c0f45f09a', 'The children sat in a ___ to play a game.', '孩子們坐成一個圓圈來玩遊戲。', 'circle', 'square', 'line', 'corner', 'circle 在此作為名詞，表示「圓圈」或「圓形」。', 'circle 的形狀就像一個圓形的甜甜圈。', '2026-07-07 04:00:59', '2026-07-07 04:00:59'),
('a9dc249e-8c3d-5f94-82b3-e329d3a29c40', 'c15483f9-99e2-4cf4-bf03-eebe349a8ce2', 'The ___ rode a horse across the farm to catch the cows.', '那位牛仔騎著馬穿過農場去抓牛。', 'cowboy', 'doctor', 'teacher', 'baker', '由 cow (牛) + boy (男孩) 組成。', '想像一個穿著牛仔褲、騎著馬的男孩 → cowboy。', '2026-07-07 10:53:01', '2026-07-07 10:53:01'),
('7f2684d5-7bed-5ffb-88e3-7a5208cb5af8', '195939be-2e71-456b-9eeb-a6a6eb961dae', 'He wants to ___ his score in the next test.', '他想在下次考試中讓分數加倍。', 'double', 'lose', 'change', 'find', 'double 的字根 du- 代表「二」。', '想像 two (二) → double (兩倍/加倍)。', '2026-07-07 05:17:59', '2026-07-07 05:17:59'),
('72cf7a0d-8ac3-57f5-8dae-adafb1dca72c', '3d83980b-06a8-4a8c-8797-8a9c2b2d538d', 'Please be careful not to ___ your phone on the floor.', '請小心不要把你的手機掉在地上。', 'drop', 'catch', 'hold', 'bring', 'drop 當動詞時，表示「使落下」或「丟下」。', '想像東西從手裡「掉」下去的樣子。', '2026-07-07 11:34:02', '2026-07-07 11:34:02'),
('8dbeaa39-e15e-5553-a248-ad8081f191ac', '5547a989-e852-4f7f-a464-04e0a4b5c673', 'My sister bought a pair of beautiful gold ___ for the party.', '我姐姐買了一對漂亮的金色耳環去參加派對。', 'earrings', 'necklaces', 'watches', 'glasses', 'ear (耳朵) + ring (環狀物) → earrings (耳環)', '想像把一個 ring (環狀物) 掛在你的 ear (耳朵) 上，就是 earrings (耳環)！', '2026-07-07 03:02:37', '2026-07-07 03:02:37'),
('aa47d201-3678-5a8e-8483-b362617a5adc', '50d82567-b36d-40c2-a180-9cbe53f57d02', 'I must study hard for my ___ exam.', '我必須為我的期末考努力讀書。', 'final', 'small', 'blue', 'happy', 'fin 表示 結束 (end)', '課程結束前的考試就是 final (期末的)', '2026-07-07 11:54:45', '2026-07-07 11:54:45'),
('7670cf9f-3f9d-5a5d-aed4-3836ad49a3f8', '3fa2477e-8225-49cb-a3ac-d14c85ab7f1d', 'They enjoy trying ___ food during their trip.', '他們在旅行期間喜歡嘗試外國食物。', 'foreign', 'sweet', 'salty', 'hot', 'foreign (adj.) 表示「外國的」或「陌生的」。', '想像去國外旅行時，看到的食物都很陌生 → foreign food (外國食物)。', '2026-07-07 12:36:31', '2026-07-07 12:36:31'),
('b5f58ea8-0a93-591e-9127-4ebda260ad80', '8a59b946-647f-49e8-af12-269c1fb6860a', 'The students come ___ the classroom.', '學生們從教室出來。', 'from', 'at', 'in', 'with', '介系詞，表示動作的起點或離開的來源。', '從某個地方「出來」或「離開」，就要用 from。', '2026-07-06 10:33:34', '2026-07-06 10:33:34'),
('e42d4863-3c9a-58b1-b22b-22a545dc7350', '6ba8bebb-72f7-41c5-ae30-b931d133d6d2', 'They will ___ to the zoo tomorrow.', '他們明天會去動物園。', 'go', 'live', 'work', 'study', 'go 表示「前往」某個地點。', 'Go to a place (去某個地方)', '2026-07-05 07:26:11', '2026-07-05 07:26:11'),
('41b4ae8c-ba23-5efb-ac3d-f79601a813e0', '70e3ae21-174d-402b-b92f-d60af3cfc873', 'The girl has beautiful, curly ___.', '那個女孩有美麗的捲髮。', 'hair', 'eyes', 'hands', 'ears', 'hair 為名詞，在此指頭髮。', 'hair 讀音像「嘿，兒」，想像在叫小孩注意他的頭髮。', '2026-07-08 06:53:09', '2026-07-08 06:53:09'),
('298513ff-8f99-51c0-ad5a-e90383c39510', '91dcf5ec-a9de-490b-a4f5-84248a8f2fa9', 'After the athlete completed the grueling marathon, ___ was exhausted but extremely proud of his achievement.', '在完成了艱辛的馬拉松之後，他感到筋疲力盡，但對自己的成就感到非常自豪。', 'he', 'she', 'they', 'it', '代名詞，用於指代單數男性。', '看到 his (他的) → 主詞對應 he。', '2026-07-06 10:50:11', '2026-07-06 10:50:11'),
('b23e8fe9-8e72-5b00-a33f-18f1c5663010', 'bdf62229-5b97-4ca6-b357-8e0d6aac7c03', 'Since ___ are responsible for your own actions, you should think carefully before making decisions.', '既然你必須為自己的行為負責，你在做決定前應該仔細思考。', 'you', 'they', 'we', 'he', 'you 為代名詞，指代對方。', 'you 聽起來像「由你」決定。', '2026-07-05 10:33:21', '2026-07-05 10:33:21');
